1	export type QuoteStep = { op: "quote"; items: Array<Record<string, unknown>> };
2	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
3	export type Step = QuoteStep | ClaimStep;
4	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	export type QuoteResult = { premium: number };
6	export type ClaimResult = { payout: number; remainingCap: number };
7	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const itemBasePremium = (item: Record<string, unknown>): number => {
13	  if (item.type === "sword") return 100;
14	  if (item.type === "amulet") return 60;
15	  return 0;
16	};
17	
18	const quotePremium = (items: Array<Record<string, unknown>>): number => {
19	  const baseSum = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
20	  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
21	  return Math.ceil(baseSum + firstInsuranceSurcharge + PROCESSING_FEE);
22	};
23	
24	export const runScenario = (scenario: Scenario): ScenarioResult => {
25	  const results = scenario.steps.map((step) => {
26	    if (step.op === "quote") {
27	      return { premium: quotePremium(step.items) };
28	    }
29	    return { payout: 0, remainingCap: 0 };
30	  });
31	  return { results };
32	};
